const res = $input.first().json;
const opps = (res.opportunities || []).filter(o => o.jobType === 'news_brief');
if (opps.length === 0) { return []; }
const opp = opps[0];
const system = [
  'You are the editor of the KarbonLens Carbon News Brief, an Indonesian carbon-market intelligence publication.',
  'RULES:',
  '- Write ORIGINAL 1-2 sentence summaries in your own words. NEVER copy phrasing from the source text.',
  '- Cite each item with a Markdown link [Source](exact-url-from-the-list). Only use URLs from the provided list.',
  '- Do not state precise figures as fact; attribute any number to its source.',
  '- On-site links must be root-relative (/prices, /projects, /regulatory). Avoid AI-tell phrases. No raw HTML.',
  '- Title <= 80 chars, summary <= 320, slug lowercase kebab-case.',
  'Return ONLY JSON: { \"kind\":\"news_brief\", \"slug\",\"title\",\"summary\",\"bodyMd\", \"sources\":[every url you cite] }.'
].join('\n');
const openaiBody = { model: 'gpt-5.5', response_format: { type: 'json_object' }, messages: [ { role: 'system', content: system }, { role: 'user', content: opp.brief } ] };
return [{ json: { opp, openaiBody } }];

const prev = $('Pick Top + Build Prompt').first().json;
const opp = prev.opp;
const ai = $input.first().json;
const content = ai.choices && ai.choices[0] && ai.choices[0].message ? ai.choices[0].message.content : '{}';
let artifact; try { artifact = JSON.parse(content); } catch (e) { throw new Error('OpenAI did not return JSON: ' + String(content).slice(0,200)); }
const usage = ai.usage || {};
return [{ json: { jobType:'news_brief', ref:opp.ref, externalId:String($execution.id), llmModel:prev.openaiBody.model, tokensIn:usage.prompt_tokens, tokensOut:usage.completion_tokens, targetQuery:opp.targetQuery, kind:'news_brief', slug:artifact.slug, title:artifact.title, summary:artifact.summary, bodyMd:artifact.bodyMd, sources:artifact.sources || [] } }];
